@kevinfowler thanks for reporting this. Would you have a chance to run pasta with the `-d` / `--debug`, `-p` / `--pcap`, and `-l` / `--log-file` options, such as:

    podman run --net=pasta:-d,-p,/tmp/ha.pcap,-l,/tmp/ha.log ...

and report back?

The error comes from ``udp_flow_sock()``:
```
        if (flowside_connect(c, s, pif, side) < 0) {
                int rc = -errno;
                flow_dbg_perror(uflow, "Couldn't connect flow socket");
                return rc;
        }
```
that is called by ``udp_flow_new()`` and then returns ``FLOW_SIDX_NONE``.
```
static flow_sidx_t udp_flow_new(const struct ctx *c, union flow *flow,
                                const struct timespec *now)
{
...
        flow_foreach_sidei(sidei) {
                if (pif_is_socket(uflow->f.pif[sidei]))
                        if ((uflow->s[sidei] = udp_flow_sock(c, uflow, sidei)) < 0)
                                goto cancel;
        }
...
cancel:
        if (uflow)
                udp_flow_close(c, uflow);
        flow_alloc_cancel(flow);
        return FLOW_SIDX_NONE;
}
```
``udp_flow_new()`` is called by ``udp_flow_from_tap()`` and ``udp_flow_from_sock()``.
For  ``udp_flow_from_tap()`` return value is used with ``udp_at_sidx()`` (in ``udp_tap_handler()``).
```
int udp_tap_handler(const struct ctx *c, uint8_t pif,
                    sa_family_t af, const void *saddr, const void *daddr,
                    uint8_t ttl, const struct pool *p, int idx,
                    const struct timespec *now)
{
...
        tosidx = udp_flow_from_tap(c, pif, af, saddr, daddr, src, dst, now);
        if (!(uflow = udp_at_sidx(tosidx))) {
```
So ``flow_at_sidx(FLOW_SIDX_NONE)`` is called and returns false (because ``sidx.flowi`` is set to ``FLOW_MAX`` in ``FLOW_SIDX_NONE``).
``flow_at_sidx()`` returns NULL and in this case the ASSERT() is ignored:
```
#define FLOW_SIDX_NONE ((flow_sidx_t){ .flowi = FLOW_MAX })
...
static inline bool flow_sidx_valid(flow_sidx_t sidx)
{
        return sidx.flowi < FLOW_MAX;
}
...
static inline union flow *flow_at_sidx(flow_sidx_t sidx)
{
        if (!flow_sidx_valid(sidx))
                return NULL;
        return FLOW(sidx.flowi);
}
...
struct udp_flow *udp_at_sidx(flow_sidx_t sidx)
{
        union flow *flow = flow_at_sidx(sidx);

        if (!flow)
                return NULL;

        ASSERT(flow->f.type == FLOW_UDP);
        return &flow->udp;
}
```
So the error and the ASSERT() are not related (this should be confirmed by a backtrace...)
(the path is very similar for ``udp_flow_from_sock()``, in ``udp_sock_fwd()``)

