``udp_flow_sock()`` calls ``flowside_sock_l4()`` and fails on ``flowside_connect()``:
```
static int udp_flow_sock(const struct ctx *c,
                         struct udp_flow *uflow, unsigned sidei)
{
...
        s = flowside_sock_l4(c, EPOLL_TYPE_UDP, pif, side, fref.data);
        if (s < 0) {
                flow_dbg_perror(uflow, "Couldn't open flow specific socket");
                return s;
        }

        if (flowside_connect(c, s, pif, side) < 0) {
                int rc = -errno;
                flow_dbg_perror(uflow, "Couldn't connect flow socket");
                return rc;
        }
...
```
But in ``flowside_sock_l4()`` we call ``sock_l4_sa()``  and it does the ``EPOLL_CTL_ADD``.

We need an ``EPOLL_CTL_DEL`` in ``udp_flow_sock()``.

Something like that:
```
diff --git a/udp_flow.c b/udp_flow.c
index fea1cf3c7a41..b3a13b7993d5 100644
--- a/udp_flow.c
+++ b/udp_flow.c
@@ -87,6 +87,10 @@ static int udp_flow_sock(const struct ctx *c,

        if (flowside_connect(c, s, pif, side) < 0) {
                int rc = -errno;
+
+               if (pif == PIF_HOST)
+                       epoll_del(c, s);
+
                flow_dbg_perror(uflow, "Couldn't connect flow socket");
                return rc;
        }
```
